    CONSTRAINT pk_fiber_quality_standard PRIMARY KEY (id),
    CONSTRAINT fk_fiber_quality_standard_iso_code FOREIGN KEY (iso_code_id) REFERENCES production.prod_fiber_iso_code(id),
