-- ===================== FROM: V20250314120000__batch_certification_change_reason.sql =====================
-- Add change_reason to batch certification (audit / GOTS compliance).
-- New records get INITIAL via application; existing rows get DEFAULT.
ALTER TABLE production.production_execution_batch_certification
    ADD COLUMN change_reason VARCHAR(30) NOT NULL DEFAULT 'INITIAL';

COMMENT ON COLUMN production.production_execution_batch_certification.change_reason IS 'Reason for this certification record: INITIAL, CORRECTION, RENEWAL, SCOPE_CHANGE, OTHER';


-- ===================== FROM: V20250314150000__batch_certification_unique_constraint.sql =====================
-- Uniqueness: one active batch certification per (batch, certification, scope);
-- for SUPPLIER scope partner_certification_id is part of the key;
-- for FACILITY scope org_certification_id is part of the key.
-- COALESCE makes NULLs comparable so BATCH scope (both null) gets a single slot per cert.
CREATE UNIQUE INDEX uq_bc_batch_cert_scope_partner_org_active
ON production.production_execution_batch_certification (
    batch_id,
    certification_id,
    scope,
    COALESCE(partner_certification_id, '00000000-0000-0000-0000-000000000000'::uuid),
    COALESCE(org_certification_id, '00000000-0000-0000-0000-000000000000'::uuid)
)
WHERE is_active = true;

COMMENT ON INDEX production.uq_bc_batch_cert_scope_partner_org_active IS
'Ensures at most one active batch certification per (batch, certification, scope, partner_cert, org_cert). SUPPLIER: partner_certification_id in key; FACILITY: org_certification_id in key.';


-- ===================== FROM: V20250314160000__batch_certification_completion_snapshot.sql =====================
-- Snapshot of certification at batch completion (GOTS TC: freeze cert at time of production).
-- Filled when batch status becomes DEPLETED (completed).
ALTER TABLE production.production_execution_batch_certification
    ADD COLUMN IF NOT EXISTS cert_number_at_completion VARCHAR(100),
    ADD COLUMN IF NOT EXISTS valid_until_at_completion DATE;

COMMENT ON COLUMN production.production_execution_batch_certification.cert_number_at_completion IS
'Cert number frozen when batch was completed (DEPLETED). GOTS TC compliance.';
COMMENT ON COLUMN production.production_execution_batch_certification.valid_until_at_completion IS
'Valid-until date frozen when batch was completed (DEPLETED). GOTS TC compliance.';


-- ===================== FROM: V20250314170000__batch_certification_is_auto_filled.sql =====================
-- Audit: was this record initially filled from autoFill (partner/facility cert)? Set to false when user edits.
ALTER TABLE production.production_execution_batch_certification
    ADD COLUMN IF NOT EXISTS is_auto_filled BOOLEAN NOT NULL DEFAULT false;

COMMENT ON COLUMN production.production_execution_batch_certification.is_auto_filled IS
'True if add used autoFill source (partner/facility cert). Set to false on any update for GOTS audit.';


-- ===================== FROM: V20250314180000__batch_certification_allow_multiple_non_overlapping.sql =====================
-- Allow multiple active batch certifications per (batch, cert, scope, partner, org) when
-- validity periods do not overlap. Overlap is enforced in application (BatchCertificationService).
DROP INDEX IF EXISTS production.uq_bc_batch_cert_scope_partner_org_active;


