-- ===================== FROM: V20260317160000__faz4_costing_module.sql =====================
-- =============================================================================
-- Phase 4: Costing Module (FAZ 4)
-- Docs: cost-structure.md, price-list.md, cost-calculation.md, exchange-rate-history.md
-- Created: 2026-03-17
-- =============================================================================

CREATE SCHEMA IF NOT EXISTS costing;

-- =============================================================================
-- 1. COST ITEMS (Global + Module-Specific)
--    System-defined — tenants cannot add rows
-- =============================================================================
CREATE TABLE IF NOT EXISTS costing.cost_item
(
    id               UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    -- tenant_id is NULL for GLOBAL system items (shared across all tenants).
    -- Tenant-specific MODULE_SPECIFIC items will have a non-null tenant_id.
    -- RLS policies must allow IS NULL tenant_id rows to pass through.
    tenant_id        UUID,
    uid              VARCHAR(100) UNIQUE,
    code             VARCHAR(50) NOT NULL UNIQUE,
    name             VARCHAR(255) NOT NULL,
    description      TEXT,
    scope            VARCHAR(30) NOT NULL, -- GLOBAL | MODULE_SPECIFIC
    module_type      VARCHAR(50),          -- FIBER | YARN | FABRIC | DYE | null (global)
    calculation_base VARCHAR(30) NOT NULL, -- PER_KG | PER_HOUR | PER_UNIT | PERCENTAGE | FIXED
    display_order    INT                  DEFAULT 0,
    is_active        BOOLEAN     NOT NULL DEFAULT TRUE,
    created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    created_by       UUID,
    updated_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_by       UUID,
    deleted_at       TIMESTAMPTZ,
    version          BIGINT      NOT NULL DEFAULT 0
);

-- Seed: 8 Global cost items (tenant_id = NULL → visible to all tenants)

-- Module-specific items (also tenant_id = NULL → system defaults, tenants can override)

-- =============================================================================
-- 2. COST TEMPLATES (Tenant-configurable)
-- =============================================================================
CREATE TABLE IF NOT EXISTS costing.cost_template
(
    id          UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id   UUID         NOT NULL,
    uid         VARCHAR(100) UNIQUE,
    name        VARCHAR(255) NOT NULL,
    module_type VARCHAR(50)  NOT NULL,
    is_default  BOOLEAN      NOT NULL    DEFAULT FALSE,
    items       JSONB        NOT NULL    DEFAULT '[]'::JSONB,
    -- items format: [{"costItemCode": "RAW_PRODUCT", "weight": 0.6, "isIncluded": true}, ...]
    is_active   BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at  TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by  UUID,
    updated_at  TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by  UUID,
    deleted_at  TIMESTAMPTZ,
    version     BIGINT       NOT NULL    DEFAULT 0
);

-- =============================================================================
-- 3. PRICE LISTS
-- =============================================================================
CREATE TABLE IF NOT EXISTS costing.price_list
(
    id          UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id   UUID         NOT NULL,
    uid         VARCHAR(100) UNIQUE,
    name        VARCHAR(255) NOT NULL,
    module_type VARCHAR(50)  NOT NULL,
    currency    VARCHAR(10)  NOT NULL    DEFAULT 'TRY',
    valid_from  DATE         NOT NULL,
    valid_until DATE,
    is_active   BOOLEAN      NOT NULL    DEFAULT TRUE,
    season_tag  VARCHAR(100),
    created_at  TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by  UUID,
    updated_at  TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by  UUID,
    deleted_at  TIMESTAMPTZ,
    version     BIGINT       NOT NULL    DEFAULT 0
);

CREATE TABLE IF NOT EXISTS costing.price_list_item
(
    id                 UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id          UUID            NOT NULL,
    uid                VARCHAR(100) UNIQUE,
    price_list_id      UUID            NOT NULL REFERENCES costing.price_list (id),
    cost_item_code     VARCHAR(50)     NOT NULL, -- FK → costing.cost_item.code (soft ref)
    product_id        UUID,                     -- nullable: product-specific
    trading_partner_id UUID,                     -- nullable: null=general, non-null=contracted
    unit_price         NUMERIC(18, 4)  NOT NULL,
    unit               VARCHAR(20)     NOT NULL,
    currency           VARCHAR(10)     NOT NULL  DEFAULT 'TRY',
    is_active          BOOLEAN         NOT NULL  DEFAULT TRUE,
    created_at         TIMESTAMPTZ     NOT NULL  DEFAULT NOW(),
    created_by         UUID,
    updated_at         TIMESTAMPTZ     NOT NULL  DEFAULT NOW(),
    updated_by         UUID,
    deleted_at         TIMESTAMPTZ,
    version            BIGINT          NOT NULL  DEFAULT 0
);

CREATE TABLE IF NOT EXISTS costing.volume_price_break
(
    id                UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id         UUID            NOT NULL,
    uid               VARCHAR(100) UNIQUE,
    price_list_item_id UUID            NOT NULL REFERENCES costing.price_list_item (id),
    min_qty           NUMERIC(15, 3)  NOT NULL,
    max_qty           NUMERIC(15, 3),
    unit_price        NUMERIC(18, 4)  NOT NULL,
    discount_rate     NUMERIC(5, 4),            -- 0.0000 – 1.0000
    is_active         BOOLEAN         NOT NULL  DEFAULT TRUE,
    created_at        TIMESTAMPTZ     NOT NULL  DEFAULT NOW(),
    created_by        UUID,
    updated_at        TIMESTAMPTZ     NOT NULL  DEFAULT NOW(),
    updated_by        UUID,
    deleted_at        TIMESTAMPTZ,
    version           BIGINT          NOT NULL  DEFAULT 0
);

-- =============================================================================
-- 4. EXCHANGE RATE SNAPSHOTS
-- =============================================================================
CREATE TABLE IF NOT EXISTS costing.exchange_rate_snapshot
(
    id              UUID PRIMARY KEY        DEFAULT gen_random_uuid(),
    tenant_id       UUID        NOT NULL,
    uid             VARCHAR(100) UNIQUE,
    base_currency   VARCHAR(10) NOT NULL    DEFAULT 'TRY',
    target_currency VARCHAR(10) NOT NULL,
    rate            NUMERIC(20, 8) NOT NULL,
    source          VARCHAR(20) NOT NULL,   -- TCMB | ECB | MANUAL
    captured_at     TIMESTAMPTZ NOT NULL,
    is_active       BOOLEAN     NOT NULL    DEFAULT TRUE,
    created_at      TIMESTAMPTZ NOT NULL    DEFAULT NOW(),
    created_by      UUID,
    updated_at      TIMESTAMPTZ NOT NULL    DEFAULT NOW(),
    updated_by      UUID,
    deleted_at      TIMESTAMPTZ,
    version         BIGINT      NOT NULL    DEFAULT 0
);

-- =============================================================================
-- 5. COST HISTORY (Price trend analysis)
-- =============================================================================
CREATE TABLE IF NOT EXISTS costing.cost_history
(
    id             UUID PRIMARY KEY        DEFAULT gen_random_uuid(),
    tenant_id      UUID            NOT NULL,
    uid            VARCHAR(100) UNIQUE,
    cost_item_code VARCHAR(50)     NOT NULL,
    module_type    VARCHAR(50),
    product_id    UUID,
    unit_price     NUMERIC(18, 4)  NOT NULL,
    currency       VARCHAR(10)     NOT NULL DEFAULT 'TRY',
    valid_from     DATE            NOT NULL,
    valid_until    DATE,
    change_reason  TEXT,
    season_tag     VARCHAR(100),
    is_active      BOOLEAN         NOT NULL DEFAULT TRUE,
    created_at     TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    created_by     UUID,
    updated_at     TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_by     UUID,
    deleted_at     TIMESTAMPTZ,
    version        BIGINT          NOT NULL DEFAULT 0
);

-- =============================================================================
-- 6. COST CALCULATIONS (Polymorphic: QUOTE / WORK_ORDER / BATCH)
-- =============================================================================
CREATE TABLE IF NOT EXISTS costing.cost_calculation
(
    id                        UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id                 UUID            NOT NULL,
    uid                       VARCHAR(100) UNIQUE,
    entity_type               VARCHAR(30)     NOT NULL, -- QUOTE | WORK_ORDER | BATCH
    entity_id                 UUID            NOT NULL,
    module_type               VARCHAR(50)     NOT NULL,
    cost_template_id          UUID REFERENCES costing.cost_template (id),
    stage                     VARCHAR(20)     NOT NULL, -- ESTIMATED | PLANNED | ACTUAL
    total_cost                NUMERIC(18, 4)  NOT NULL DEFAULT 0,
    currency                  VARCHAR(10)     NOT NULL DEFAULT 'TRY',
    calculated_at             TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    exchange_rate_snapshot_id UUID REFERENCES costing.exchange_rate_snapshot (id),
    notes                     TEXT,
    is_active                 BOOLEAN         NOT NULL DEFAULT TRUE,
    created_at                TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    created_by                UUID,
    updated_at                TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_by                UUID,
    deleted_at                TIMESTAMPTZ,
    version                   BIGINT          NOT NULL DEFAULT 0
);

CREATE TABLE IF NOT EXISTS costing.cost_calculation_line
(
    id                    UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id             UUID            NOT NULL,
    uid                   VARCHAR(100) UNIQUE,
    cost_calculation_id   UUID            NOT NULL REFERENCES costing.cost_calculation (id),
    cost_item_code        VARCHAR(50)     NOT NULL,
    qty                   NUMERIC(15, 3),
    unit                  VARCHAR(20),
    unit_price            NUMERIC(18, 4)  NOT NULL,
    currency              VARCHAR(10)     NOT NULL DEFAULT 'TRY',
    total_in_base_currency NUMERIC(18, 4) NOT NULL DEFAULT 0,
    exchange_rate         NUMERIC(20, 8),
    volume_discount_applied BOOLEAN       NOT NULL DEFAULT FALSE,
    notes                 TEXT,
    is_active             BOOLEAN         NOT NULL DEFAULT TRUE,
    created_at            TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    created_by            UUID,
    updated_at            TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
    updated_by            UUID,
    deleted_at            TIMESTAMPTZ,
    version               BIGINT          NOT NULL DEFAULT 0
);

-- =============================================================================
-- INDEXES
-- =============================================================================
CREATE INDEX IF NOT EXISTS idx_cost_template_tenant ON costing.cost_template (tenant_id, module_type);
CREATE INDEX IF NOT EXISTS idx_price_list_tenant ON costing.price_list (tenant_id, is_active, valid_from);
CREATE INDEX IF NOT EXISTS idx_price_list_item_list ON costing.price_list_item (price_list_id, cost_item_code);
CREATE INDEX IF NOT EXISTS idx_price_list_item_partner ON costing.price_list_item (trading_partner_id) WHERE trading_partner_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_volume_break_item ON costing.volume_price_break (price_list_item_id);
CREATE INDEX IF NOT EXISTS idx_exchange_rate_currencies ON costing.exchange_rate_snapshot (base_currency, target_currency, captured_at DESC);
CREATE INDEX IF NOT EXISTS idx_cost_history_item ON costing.cost_history (cost_item_code, product_id, valid_from);
CREATE INDEX IF NOT EXISTS idx_cost_calc_entity ON costing.cost_calculation (entity_type, entity_id, stage);
CREATE INDEX IF NOT EXISTS idx_cost_calc_line_calc ON costing.cost_calculation_line (cost_calculation_id);


-- ===================== FROM: V20260318090000__faz5_sales_expansion.sql =====================
-- =============================================================================
-- Phase 5: Sales Expansion (FAZ 5)
-- Docs: sales-product.md, discount-policy.md, quote-approval.md, sample-management.md
-- Created: 2026-03-18
-- =============================================================================

CREATE SCHEMA IF NOT EXISTS sales;

-- =============================================================================
-- 1. DISCOUNT POLICY (Tenant-level Kâr Marjı ve İndirim Kuralları)
-- =============================================================================
CREATE TABLE IF NOT EXISTS sales.discount_policy
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    module_type         VARCHAR(50)  NOT NULL, -- FIBER | YARN | FABRIC | DYE_FINISHING
    base_discount_limit NUMERIC(5, 4) NOT NULL   DEFAULT 0.1000, -- %10
    min_profit_margin   NUMERIC(5, 4) NOT NULL   DEFAULT 0.0500, -- %5 (Kırmızı Çizgi)
    require_manager_above NUMERIC(5, 4) NOT NULL DEFAULT 0.1000, -- %10
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    deleted_at          TIMESTAMPTZ,
    version             BIGINT       NOT NULL    DEFAULT 0
);

-- =============================================================================
-- 2. PRODUCT CATALOG (Fuar / Offline Satış Katalog Ürünleri)
-- =============================================================================
CREATE TABLE IF NOT EXISTS sales.sales_product
(
    id             UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id      UUID         NOT NULL,
    uid            VARCHAR(100) UNIQUE,
    product_id    UUID         NOT NULL, -- FK → production.product
    module_type    VARCHAR(50)  NOT NULL,
    list_price     NUMERIC(18, 4) NOT NULL, -- Baz liste fiyatı
    currency       VARCHAR(10)  NOT NULL    DEFAULT 'TRY',
    moq            NUMERIC(15, 3),          -- Minimum sipariş miktarı
    moq_unit       VARCHAR(20),             -- KG, MT, PIECE
    lead_time_days INT,                     -- Teslimat süresi (gün)
    specs          JSONB        NOT NULL    DEFAULT '{}'::JSONB,
    photos         JSONB        NOT NULL    DEFAULT '[]'::JSONB,
    is_active      BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at     TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by     UUID,
    updated_at     TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by     UUID,
    deleted_at     TIMESTAMPTZ,
    version        BIGINT       NOT NULL    DEFAULT 0
);

-- =============================================================================
-- 3. QUOTE & QUOTE_LINE (Satış Teklifi)
-- =============================================================================
CREATE TABLE IF NOT EXISTS sales.quote
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    quote_number        VARCHAR(50)  NOT NULL UNIQUE, -- QT-2024-001 vb.
    customer_id         UUID         NOT NULL, -- FK → master_data.trading_partner
    assigned_to_id      UUID         NOT NULL, -- Pazarlamacı (FK → User)
    module_type         VARCHAR(50)  NOT NULL,
    status              VARCHAR(30)  NOT NULL    DEFAULT 'DRAFT', -- DRAFT, PENDING_APPROVAL vb.
    estimated_unit_cost NUMERIC(18, 4),        -- CostCalculation module'den
    valid_until         DATE         NOT NULL,
    payment_terms       VARCHAR(50),           -- CASH, NET_30 vb.
    lead_time_days      INT,
    notes               TEXT,
    attachments         JSONB        NOT NULL    DEFAULT '[]'::JSONB,
    revision_number     INT          NOT NULL    DEFAULT 1,
    parent_quote_id     UUID REFERENCES sales.quote (id), -- Revize edilen atası
    offline_id          UUID,
    offline_device_id   VARCHAR(100),
    offline_created_at  TIMESTAMP WITH TIME ZONE,
    synced_at           TIMESTAMP WITH TIME ZONE,
    sync_status         VARCHAR(20),
    sync_conflict_reason TEXT,
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    deleted_at          TIMESTAMPTZ,
    version             BIGINT       NOT NULL    DEFAULT 0
);

CREATE TABLE IF NOT EXISTS sales.quote_line
(
    id              UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id       UUID         NOT NULL,
    uid             VARCHAR(100) UNIQUE,
    quote_id        UUID         NOT NULL REFERENCES sales.quote (id),
    product_id     UUID,                  -- katalog ürünü
    product_desc    TEXT,                  -- özel/serbest tanım
    requested_qty   NUMERIC(15, 3) NOT NULL,
    unit            VARCHAR(20)  NOT NULL,
    list_price      NUMERIC(18, 4) NOT NULL,
    offered_price   NUMERIC(18, 4) NOT NULL,
    discount_rate   NUMERIC(5, 4)  NOT NULL, -- Otomatik hesaplanır ([list-offered]/list)
    profit_margin   NUMERIC(5, 4),           -- Otomatik hesaplanır ([offered-cost]/offered)
    price_zone      VARCHAR(30)  NOT NULL, -- FREE | MANAGER_APPROVAL | BLOCKED
    module_specs    JSONB        NOT NULL    DEFAULT '{}'::JSONB,
    is_active       BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at      TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by      UUID,
    updated_at      TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by      UUID,
    deleted_at      TIMESTAMPTZ,
    version         BIGINT       NOT NULL    DEFAULT 0
);

-- =============================================================================
-- 4. QUOTE APPROVAL TOKEN (Müşteri Onay Linkleri)
-- =============================================================================
CREATE TABLE IF NOT EXISTS sales.quote_approval_token
(
    id              UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id       UUID         NOT NULL,
    uid             VARCHAR(100) UNIQUE,
    quote_id        UUID         NOT NULL REFERENCES sales.quote (id),
    token           VARCHAR(255) NOT NULL UNIQUE,
    channel         VARCHAR(30)  NOT NULL, -- EMAIL | WHATSAPP | IN_PERSON
    sent_to         VARCHAR(255),          -- E-posta adresi / tel no
    expires_at      TIMESTAMPTZ  NOT NULL,
    status          VARCHAR(30)  NOT NULL    DEFAULT 'PENDING', -- PENDING | USED | EXPIRED
    used_at         TIMESTAMPTZ,
    ip_address      VARCHAR(50),
    user_agent      TEXT,
    location        JSONB,                 -- Enlem / Boylam lokasyon verisi
    is_active       BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at      TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by      UUID,
    updated_at      TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by      UUID,
    deleted_at      TIMESTAMPTZ,
    version         BIGINT       NOT NULL    DEFAULT 0
);

-- =============================================================================
-- 5. SAMPLE MANAGEMENT (Numune Talebi ve Teslimatı)
-- =============================================================================
CREATE TABLE IF NOT EXISTS sales.sample_request
(
    id               UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id        UUID         NOT NULL,
    uid              VARCHAR(100) UNIQUE,
    customer_id      UUID         NOT NULL, -- FK → master_data.trading_partner
    product_id      UUID         NOT NULL, -- FK → production.product
    requested_qty    NUMERIC(15, 3) NOT NULL,
    unit             VARCHAR(20)  NOT NULL,
    delivery_method  VARCHAR(30)  NOT NULL, -- CARGO | SALESPERSON | DELIVERY_ROUTE
    delivery_address JSONB,                 -- Alıcı adresi
    status           VARCHAR(30)  NOT NULL    DEFAULT 'REQUESTED',
    sales_order_id   UUID,                  -- Sonradan siparişe dönerse
    notes            TEXT,
    is_active        BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at       TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by       UUID,
    updated_at       TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by       UUID,
    deleted_at       TIMESTAMPTZ,
    version          BIGINT       NOT NULL    DEFAULT 0
);

CREATE TABLE IF NOT EXISTS sales.sample_delivery
(
    id                UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id         UUID         NOT NULL,
    uid               VARCHAR(100) UNIQUE,
    sample_request_id UUID         NOT NULL REFERENCES sales.sample_request (id),
    delivery_method   VARCHAR(30)  NOT NULL, -- CARGO | SALESPERSON
    tracking_number   VARCHAR(100),          -- Kargo numarası
    cargo_company     VARCHAR(100),          -- DHL, PTT vs.
    delivered_by_id   UUID,                  -- FK → User (eğer salesperson teslim ettiyse)
    dispatched_at     TIMESTAMPTZ,           -- Gönderim tarihi
    delivered_at      TIMESTAMPTZ,           -- Ulaşım tarihi
    recipient_name    VARCHAR(255),          -- Teslim alan kim?
    delivery_photo    TEXT,                  -- Teslimat kanıtı fotoğraf URL'si
    is_active         BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at        TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by        UUID,
    updated_at        TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by        UUID,
    deleted_at        TIMESTAMPTZ,
    version           BIGINT       NOT NULL    DEFAULT 0
);

-- =============================================================================
-- INDEXES
-- =============================================================================
CREATE INDEX IF NOT EXISTS idx_sales_discount_policy_tenant ON sales.discount_policy(tenant_id, module_type);
CREATE INDEX IF NOT EXISTS idx_sales_sales_product_tenant ON sales.sales_product(tenant_id, module_type);
CREATE INDEX IF NOT EXISTS idx_sales_sales_product_product ON sales.sales_product(product_id);

CREATE INDEX IF NOT EXISTS idx_sales_quote_tenant_customer ON sales.quote(tenant_id, customer_id);
CREATE INDEX IF NOT EXISTS idx_sales_quote_number ON sales.quote(quote_number);
CREATE INDEX IF NOT EXISTS idx_sales_quote_line_quote ON sales.quote_line(quote_id);
CREATE INDEX IF NOT EXISTS idx_sales_quote_token ON sales.quote_approval_token(token);
CREATE INDEX IF NOT EXISTS idx_sales_quote_parent ON sales.quote(parent_quote_id);

CREATE INDEX IF NOT EXISTS idx_sales_sample_req_tenant_customer ON sales.sample_request(tenant_id, customer_id);
CREATE INDEX IF NOT EXISTS idx_sales_sample_delivery_req ON sales.sample_delivery(sample_request_id);


