-- ===================== FROM: V20260320120000__faz8_2_smart_task_generator.sql =====================
-- =============================================================================
-- Faz 8.2: FlowBoard — SmartTaskGenerator + AutomationEngine
-- Docs: 07-flowboard/smart-task-generator.md (v2.0)
-- Created: 2026-03-20
-- Schema: flowboard
-- Tables: task_template, automation_rule
--
-- TODO-TECHDEBT [M1] Rollback:
--   Bu migration'ı geri almak için:
--   DROP TABLE IF EXISTS flowboard.automation_rule;
--   DROP TABLE IF EXISTS flowboard.task_template;
-- =============================================================================

-- =============================================================================
-- 8.2.1 — TASK TEMPLATE
-- Event → Task eşleme şablonları
-- =============================================================================

CREATE TABLE IF NOT EXISTS flowboard.task_template
(
    id                      UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id               UUID         NOT NULL,
    uid                     VARCHAR(100) UNIQUE,
    event_type              VARCHAR(100) NOT NULL,   -- "SalesOrderConfirmed", "BatchQcFailed"
    title_template          VARCHAR(500) NOT NULL,   -- "{salesOrder.orderNumber}" placeholder'lar
    task_type               VARCHAR(30)  NOT NULL,
    module_type             VARCHAR(30),             -- NULL = tüm modüller
    default_priority        VARCHAR(10)  NOT NULL    DEFAULT 'MEDIUM',
    default_assignee_role   VARCHAR(20)  NOT NULL    DEFAULT 'ANY',
    estimated_hours         NUMERIC(6,2),
    checklist_template      TEXT,                    -- JSONB format: [{"title":"...","order":1}]
    auto_labels             TEXT,                    -- JSONB format: ["URGENT","VIP_CLIENT"]
    is_active               BOOLEAN      NOT NULL    DEFAULT TRUE,
    deleted_at              TIMESTAMPTZ,
    created_at              TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by              UUID,
    updated_at              TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by              UUID,
    version                 BIGINT       NOT NULL    DEFAULT 0,
    CONSTRAINT chk_task_template_task_type CHECK (task_type IN (
        'PLANNING','PRODUCTION','QUALITY','WAREHOUSE','SHIPMENT',
        'APPROVAL','RECIPE_ASSIGNMENT','PROCUREMENT','COSTING',
        'SAMPLE','RETURN','STOCK_COUNT','MAINTENANCE','GENERAL'
    )),
    CONSTRAINT chk_task_template_priority CHECK (default_priority IN ('LOW','MEDIUM','HIGH','CRITICAL')),
    CONSTRAINT chk_task_template_assignee_role CHECK (default_assignee_role IN ('DEPARTMENT_ADMIN','MANAGER','ANY'))
);

-- =============================================================================
-- 8.2.2 — AUTOMATION RULE
-- If-Then-That otomasyon kuralları
-- =============================================================================

CREATE TABLE IF NOT EXISTS flowboard.automation_rule
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    name                VARCHAR(255) NOT NULL,
    description         TEXT,
    trigger_type        VARCHAR(40)  NOT NULL,
    trigger_config      TEXT         NOT NULL,    -- JSONB: {"fromStatus":"IN_PROGRESS","toStatus":"DONE"}
    condition_config    TEXT,                     -- JSONB: {"taskType":"QUALITY"} — null = her zaman
    action_type         VARCHAR(30)  NOT NULL,
    action_config       TEXT         NOT NULL,    -- JSONB: {"newStatus":"IN_REVIEW"}
    board_id            UUID         REFERENCES flowboard.board (id),  -- null = global
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    execution_count     BIGINT       NOT NULL    DEFAULT 0,
    last_executed_at    TIMESTAMPTZ,
    created_by_user_id  UUID,
    deleted_at          TIMESTAMPTZ,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    version             BIGINT       NOT NULL    DEFAULT 0,
    CONSTRAINT chk_automation_trigger_type CHECK (trigger_type IN (
        'STATUS_CHANGED','DEADLINE_APPROACHING','TASK_ASSIGNED',
        'TASK_UNASSIGNED_TOO_LONG','LABEL_ADDED','LABEL_REMOVED',
        'CHECKLIST_COMPLETED','TIMER_EXCEEDED','WIP_EXCEEDED','PRIORITY_CHANGED'
    )),
    CONSTRAINT chk_automation_action_type CHECK (action_type IN (
        'CHANGE_STATUS','ASSIGN_USER','ASSIGN_DEPARTMENT','NOTIFY_USER',
        'NOTIFY_MANAGER','CREATE_TASK','ADD_LABEL','REMOVE_LABEL',
        'UPDATE_PRIORITY','ESCALATE'
    ))
);

-- =============================================================================
-- INDEXES
-- =============================================================================

CREATE INDEX IF NOT EXISTS idx_task_template_event_type ON flowboard.task_template (event_type, is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_task_template_tenant    ON flowboard.task_template (tenant_id);

CREATE INDEX IF NOT EXISTS idx_automation_rule_board   ON flowboard.automation_rule (board_id) WHERE board_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_automation_rule_trigger ON flowboard.automation_rule (trigger_type, is_active) WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_automation_rule_global  ON flowboard.automation_rule (is_active, trigger_type) WHERE board_id IS NULL AND is_active = TRUE;

-- =============================================================================
-- SEED DATA — 15 TaskTemplate (Global — tenant_id gerekli ama seed null değil)
-- NOT: tenant_id alanı seed'de sistem UUID'i ile doldurulur.
--      Gerçek tenant verileri onboard sırasında kopyalanır.
--      Bu seed'ler template_id ile ilişkilendirilmek üzere saklanır.
-- =============================================================================

-- Sistem seed tenant UUID (sabit — tüm tenant'lar için referans)
DO $$
DECLARE
    seed_tenant UUID := '00000000-0000-0000-0000-000000000001';
BEGIN

-- 1. SalesOrderConfirmed → PLANNING

-- 2. WorkOrderPendingApproval → APPROVAL

-- 3. WorkOrderApproved → PRODUCTION

-- 4. BatchQcPending → QUALITY

-- 5. BatchQcFailed → QUALITY (CRITICAL)

-- 6. GoodsReceiptConfirmed → WAREHOUSE

-- 7. SalesOrderInWarehouse → SHIPMENT

-- 8. RecipeAssignmentNeeded → RECIPE_ASSIGNMENT

-- 9. MinStockAlert → PROCUREMENT

-- 10. PoDeliveryLate → PROCUREMENT

-- 11. CostVarianceDetected → COSTING

-- 12. ReturnRateExceeded → RETURN

-- 13. ApprovalPending → APPROVAL

-- 14. UserPromotionReady → APPROVAL

-- 15. SupplierLicenseExpiringSoon → GENERAL

-- =============================================================================
-- SEED DATA — 8 AutomationRule (Global — board_id NULL)
-- =============================================================================

-- 1. QC bitti → depo görevi

-- 2. Kritik deadline uyarısı

-- 3. WIP aşımı uyarısı

-- 4. Büyük task tıkandı → eskalasyon

-- 5. VIP etiketi → öncelik artır

-- 6. Checklist tamamlandı → IN_REVIEW

-- 7. Süre aşıldı → URGENT etiketi + manager bildirimi

-- 8. Atanmamış task uyarısı

END $$;


-- ===================== FROM: V20260321120000__faz8_3_task_details_escalation.sql =====================
-- =============================================================================
-- Faz 8.3: FlowBoard — Task Detayları ve Eskalasyon
-- Docs: 07-flowboard/task-details.md, 07-flowboard/escalation.md (v2.0)
-- Schema: flowboard
-- Tables: task_checklist, task_comment, task_activity_log, task_dependency, 
--         task_time_entry, task_attachment, task_reminder, task_relation,
--         escalation_log
-- =============================================================================

-- =============================================================================
-- 1. TASK CHECKLIST
-- =============================================================================

CREATE TABLE IF NOT EXISTS flowboard.task_checklist
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    task_id             UUID         NOT NULL REFERENCES flowboard.task (id),
    title               VARCHAR(255) NOT NULL,
    is_completed        BOOLEAN      NOT NULL    DEFAULT FALSE,
    completed_at        TIMESTAMPTZ,
    completed_by_user_id UUID,
    display_order       INTEGER      NOT NULL    DEFAULT 1,
    deleted_at          TIMESTAMPTZ,
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    version             BIGINT       NOT NULL    DEFAULT 0
);
CREATE INDEX idx_task_checklist_task ON flowboard.task_checklist (task_id);

-- =============================================================================
-- 2. TASK COMMENT
-- =============================================================================

CREATE TABLE IF NOT EXISTS flowboard.task_comment
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    task_id             UUID         NOT NULL REFERENCES flowboard.task (id),
    user_id             UUID         NOT NULL,
    content             TEXT         NOT NULL,
    mentioned_user_ids  TEXT,                   -- JSONB
    deleted_at          TIMESTAMPTZ,
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    version             BIGINT       NOT NULL    DEFAULT 0
);
CREATE INDEX idx_task_comment_task ON flowboard.task_comment (task_id);

-- =============================================================================
-- 3. TASK ACTIVITY LOG
-- =============================================================================

CREATE TABLE IF NOT EXISTS flowboard.task_activity_log
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    task_id             UUID         NOT NULL REFERENCES flowboard.task (id),
    user_id             UUID,                   -- null ise SYSTEM
    action              VARCHAR(40)  NOT NULL,  -- Enum: STATUS_CHANGED, COMMENTED vs.
    old_value           VARCHAR(255),
    new_value           VARCHAR(255),
    metadata            TEXT,                   -- JSONB
    deleted_at          TIMESTAMPTZ,
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    version             BIGINT       NOT NULL    DEFAULT 0
);
CREATE INDEX idx_task_activity_log_task ON flowboard.task_activity_log (task_id);
CREATE INDEX idx_task_activity_log_action ON flowboard.task_activity_log (action);

-- =============================================================================
-- 4. TASK DEPENDENCY
-- =============================================================================
-- Tablo artık BaseEntity extend ediyor
CREATE TABLE IF NOT EXISTS flowboard.task_dependency
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    task_id             UUID         NOT NULL REFERENCES flowboard.task (id),
    depends_on_task_id  UUID         NOT NULL REFERENCES flowboard.task (id),
    dependency_type     VARCHAR(20)  NOT NULL,  -- FINISH_TO_START, START_TO_START, PARALLEL
    deleted_at          TIMESTAMPTZ,
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    version             BIGINT       NOT NULL    DEFAULT 0
);
CREATE UNIQUE INDEX uk_task_dependency ON flowboard.task_dependency (task_id, depends_on_task_id);
CREATE INDEX idx_task_dependency_depends_on ON flowboard.task_dependency (depends_on_task_id);

-- =============================================================================
-- 5. TASK TIME ENTRY
-- =============================================================================

CREATE TABLE IF NOT EXISTS flowboard.task_time_entry
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    task_id             UUID         NOT NULL REFERENCES flowboard.task (id),
    user_id             UUID         NOT NULL,
    started_at          TIMESTAMPTZ  NOT NULL,
    ended_at            TIMESTAMPTZ,
    duration_minutes    INTEGER,
    entry_type          VARCHAR(20)  NOT NULL,  -- TIMER, MANUAL
    note                VARCHAR(500),
    deleted_at          TIMESTAMPTZ,
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    version             BIGINT       NOT NULL    DEFAULT 0
);
CREATE INDEX idx_task_time_entry_task ON flowboard.task_time_entry (task_id);
CREATE INDEX idx_task_time_entry_user ON flowboard.task_time_entry (user_id);
-- Tek aktif timer kontrolü için partial unique index
CREATE UNIQUE INDEX uk_task_time_entry_active_timer 
    ON flowboard.task_time_entry (user_id) 
    WHERE ended_at IS NULL AND deleted_at IS NULL;

-- =============================================================================
-- 6. TASK ATTACHMENT
-- =============================================================================

CREATE TABLE IF NOT EXISTS flowboard.task_attachment
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    task_id             UUID         NOT NULL REFERENCES flowboard.task (id),
    file_name           VARCHAR(500) NOT NULL,
    file_type           VARCHAR(50)  NOT NULL,
    file_size_bytes     BIGINT       NOT NULL,
    storage_path        VARCHAR(1000) NOT NULL,
    uploaded_by_user_id UUID         NOT NULL,
    attachment_type     VARCHAR(20)  NOT NULL,  -- DOCUMENT, IMAGE, REPORT, OTHER
    description         VARCHAR(255),
    deleted_at          TIMESTAMPTZ,
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    version             BIGINT       NOT NULL    DEFAULT 0
);
CREATE INDEX idx_task_attachment_task ON flowboard.task_attachment (task_id);

-- =============================================================================
-- 7. TASK REMINDER
-- =============================================================================

CREATE TABLE IF NOT EXISTS flowboard.task_reminder
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    task_id             UUID         NOT NULL REFERENCES flowboard.task (id),
    user_id             UUID         NOT NULL,
    reminder_type       VARCHAR(30)  NOT NULL,  -- MANUAL, DEADLINE_OFFSET, FOLLOW_UP
    trigger_at          TIMESTAMPTZ  NOT NULL,
    offset_minutes      INTEGER,
    message             VARCHAR(500),
    is_sent             BOOLEAN      NOT NULL    DEFAULT FALSE,
    sent_at             TIMESTAMPTZ,
    channel             VARCHAR(20)  NOT NULL,  -- IN_APP, EMAIL, BOTH
    deleted_at          TIMESTAMPTZ,
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    version             BIGINT       NOT NULL    DEFAULT 0
);
CREATE INDEX idx_task_reminder_task ON flowboard.task_reminder (task_id);
CREATE INDEX idx_task_reminder_trigger ON flowboard.task_reminder (trigger_at) WHERE is_sent = FALSE AND deleted_at IS NULL;

-- =============================================================================
-- 8. TASK RELATION (Cross-Board Link)
-- =============================================================================

CREATE TABLE IF NOT EXISTS flowboard.task_relation
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    source_task_id      UUID         NOT NULL REFERENCES flowboard.task (id),
    target_task_id      UUID         NOT NULL REFERENCES flowboard.task (id),
    relation_type       VARCHAR(30)  NOT NULL,  -- RELATED, DUPLICATES, CAUSED_BY, PARENT_CHILD
    created_by_user_id  UUID         NOT NULL,
    note                VARCHAR(255),
    deleted_at          TIMESTAMPTZ,
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    version             BIGINT       NOT NULL    DEFAULT 0
);
CREATE UNIQUE INDEX uk_task_relation ON flowboard.task_relation (source_task_id, target_task_id) WHERE deleted_at IS NULL;
CREATE INDEX idx_task_relation_target ON flowboard.task_relation (target_task_id);

-- =============================================================================
-- 9. ESCALATION LOG
-- =============================================================================

CREATE TABLE IF NOT EXISTS flowboard.escalation_log
(
    id                  UUID PRIMARY KEY         DEFAULT gen_random_uuid(),
    tenant_id           UUID         NOT NULL,
    uid                 VARCHAR(100) UNIQUE,
    task_id             UUID         NOT NULL REFERENCES flowboard.task (id),
    escalation_type     VARCHAR(30)  NOT NULL,  -- DEADLINE_PASSED, UNASSIGNED, BLOCKED_TOO_LONG vs
    escalated_to_user_id UUID        NOT NULL,
    message             VARCHAR(500) NOT NULL,
    resolved_at         TIMESTAMPTZ,
    resolved_by_user_id UUID,
    resolution_note     VARCHAR(500),
    deleted_at          TIMESTAMPTZ,
    is_active           BOOLEAN      NOT NULL    DEFAULT TRUE,
    created_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    created_by          UUID,
    updated_at          TIMESTAMPTZ  NOT NULL    DEFAULT NOW(),
    updated_by          UUID,
    version             BIGINT       NOT NULL    DEFAULT 0
);
CREATE INDEX idx_escalation_log_task ON flowboard.escalation_log (task_id);
CREATE INDEX idx_escalation_log_type ON flowboard.escalation_log (escalation_type) WHERE deleted_at IS NULL;


