-- ===================== FROM: V20260401150000__sprint6_add_product_id_to_consumption.sql =====================
-- Sprint 6: Denormalize product_id onto work_order_consumption for cost calculation
-- Without this, multi-product cost lookup requires joining to the batch table at query time.

ALTER TABLE production.work_order_consumption
    ADD COLUMN IF NOT EXISTS product_id UUID;

-- Backfill from the batch table (safe: uses existing batch_id FK)
UPDATE production.work_order_consumption woc
SET product_id = b.product_id
FROM production.production_execution_batch b
WHERE b.id = woc.batch_id
  AND woc.product_id IS NULL;

-- Index for cost engine queries (tenant + product scoped)
CREATE INDEX IF NOT EXISTS idx_wo_consumption_product
    ON production.work_order_consumption (tenant_id, product_id)
    WHERE product_id IS NOT NULL;


-- ===================== FROM: V20260401160000__add_product_id_to_cost_calculation_line.sql =====================
-- Sprint 7a: Add proper product_id column to cost_calculation_line
-- Replaces the text-based "productId=UUID" tracking in notes field.

ALTER TABLE costing.cost_calculation_line
    ADD COLUMN IF NOT EXISTS product_id UUID;

-- Backfill from notes field (Sprint 6 data)
UPDATE costing.cost_calculation_line
SET product_id = CAST(
    SUBSTRING(notes FROM 'productId=([0-9a-f\-]{36})') AS UUID
)
WHERE notes LIKE 'productId=%'
  AND product_id IS NULL;

-- Index for per-product cost breakdown queries
CREATE INDEX IF NOT EXISTS idx_ccline_product
    ON costing.cost_calculation_line (tenant_id, product_id)
    WHERE product_id IS NOT NULL AND is_active = true;


-- ===================== FROM: V20260401170000__sprint9_workorder_filter_indexes.sql =====================
-- Sprint 9: Composite indexes for Specification-based filtering.
-- Without these, dynamic WHERE clauses trigger sequential scans on the work order table.

CREATE INDEX IF NOT EXISTS idx_wo_tenant_status
    ON production.prod_work_order (tenant_id, status)
    WHERE is_active = true;

CREATE INDEX IF NOT EXISTS idx_wo_tenant_partner
    ON production.prod_work_order (tenant_id, trading_partner_id)
    WHERE is_active = true;

CREATE INDEX IF NOT EXISTS idx_wo_tenant_deadline
    ON production.prod_work_order (tenant_id, deadline)
    WHERE is_active = true;

CREATE INDEX IF NOT EXISTS idx_wo_tenant_sales_order
    ON production.prod_work_order (tenant_id, sales_order_id)
    WHERE is_active = true;

-- workOrderNumber already has a unique constraint but adding partial index
-- for the common tenant + active filter combination used by searchText
CREATE INDEX IF NOT EXISTS idx_wo_tenant_wonumber
    ON production.prod_work_order (tenant_id, work_order_number)
    WHERE is_active = true;


-- ===================== FROM: V20260401180000__sprint11_planned_cost_writeback.sql =====================
-- V20260401180000__sprint11_planned_cost_writeback.sql
ALTER TABLE production.prod_work_order 
    ADD COLUMN IF NOT EXISTS planned_cost NUMERIC(15,3);

ALTER TABLE production.prod_work_order 
    ADD COLUMN IF NOT EXISTS planned_cost_currency VARCHAR(3);

-- Backfill: mevcut WO'lar için unit_cost * planned_qty hesapla
UPDATE production.prod_work_order 
SET planned_cost = unit_cost * planned_qty,
    planned_cost_currency = currency
WHERE planned_cost IS NULL 
  AND unit_cost IS NOT NULL 
  AND planned_qty IS NOT NULL
  AND is_active = true;

COMMENT ON COLUMN production.prod_work_order.planned_cost IS 
    'Written by CostCalculationService.computePlanned() — Sprint 11';


